// src/components/UI/ObjectControls.jsx
// UI component for controlling selected objects

import React from 'react';

const ObjectControls = ({ selectedObject, onObjectAction, transformMode }) => {
  if (!selectedObject) return null;
  
  // Check if object is pinned
  const isPinned = selectedObject.userData && selectedObject.userData.isPinned;
  
  // Handle transform mode button clicks
  const handleModeClick = (mode) => {
    onObjectAction(mode);
  };
  
  // Handle object action clicks
  const handleActionClick = (action) => {
    onObjectAction(action);
  };
  
  // Handle rotation
  const handleRotate = (degrees) => {
    onObjectAction('rotate-by', degrees);
  };
  
  // Define styles as a JavaScript object
  const styles = {
    objectControls: {
      position: 'absolute',
      top: '10px',
      right: '10px',
      backgroundColor: 'rgba(30, 30, 30, 0.8)',
      color: 'white',
      padding: '15px',
      borderRadius: '8px',
      width: '250px',
      boxShadow: '0 2px 10px rgba(0,0,0,0.3)',
    },
    heading: {
      marginTop: 0,
      paddingBottom: '10px',
      borderBottom: '1px solid rgba(255,255,255,0.2)',
      textTransform: 'capitalize',
    },
    subHeading: {
      margin: '10px 0 5px',
      fontSize: '14px',
    },
    controlSection: {
      marginBottom: '15px',
    },
    buttonGroup: {
      display: 'flex',
      flexWrap: 'wrap',
      gap: '5px',
    },
    button: {
      padding: '8px 12px',
      backgroundColor: '#444',
      border: 'none',
      borderRadius: '4px',
      color: 'white',
      cursor: 'pointer',
      fontSize: '12px',
      flexGrow: 1,
    },
    activeButton: {
      backgroundColor: '#0088ff',
    },
    pinnedButton: {
      backgroundColor: '#ff3366',
    },
    disabledButton: {
      opacity: 0.5,
      cursor: 'not-allowed',
    },
    dangerButton: {
      backgroundColor: '#ff3333',
    },
    shortcutHints: {
      marginTop: '15px',
      fontSize: '11px',
      color: 'rgba(255,255,255,0.6)',
      textAlign: 'center',
    }
  };

  return (
    <div style={styles.objectControls}>
      <h3 style={styles.heading}>Selected: {selectedObject.userData ? selectedObject.userData.type : 'Object'}</h3>
      
      <div style={styles.controlSection}>
        <h4 style={styles.subHeading}>Transform</h4>
        <div style={styles.buttonGroup}>
          <button 
            style={{
              ...styles.button,
              ...(transformMode === 'translate' ? styles.activeButton : {}),
              ...(isPinned ? styles.disabledButton : {})
            }}
            onClick={() => handleModeClick('translate')}
            disabled={isPinned}
          >
            Move
          </button>
          <button 
            style={{
              ...styles.button,
              ...(transformMode === 'rotate' ? styles.activeButton : {}),
              ...(isPinned ? styles.disabledButton : {})
            }}
            onClick={() => handleModeClick('rotate')}
            disabled={isPinned}
          >
            Rotate
          </button>
          <button 
            style={{
              ...styles.button,
              ...(transformMode === 'scale' ? styles.activeButton : {}),
              ...(isPinned ? styles.disabledButton : {})
            }}
            onClick={() => handleModeClick('scale')}
            disabled={isPinned}
          >
            Scale
          </button>
        </div>
      </div>
      
      <div style={styles.controlSection}>
        <h4 style={styles.subHeading}>Quick Rotation</h4>
        <div style={styles.buttonGroup}>
          <button 
            style={{
              ...styles.button,
              ...(isPinned ? styles.disabledButton : {})
            }}
            onClick={() => handleRotate(-90)}
            disabled={isPinned}
          >
            -90°
          </button>
          <button 
            style={{
              ...styles.button,
              ...(isPinned ? styles.disabledButton : {})
            }}
            onClick={() => handleRotate(-45)}
            disabled={isPinned}
          >
            -45°
          </button>
          <button 
            style={{
              ...styles.button,
              ...(isPinned ? styles.disabledButton : {})
            }}
            onClick={() => handleRotate(45)}
            disabled={isPinned}
          >
            +45°
          </button>
          <button 
            style={{
              ...styles.button,
              ...(isPinned ? styles.disabledButton : {})
            }}
            onClick={() => handleRotate(90)}
            disabled={isPinned}
          >
            +90°
          </button>
        </div>
      </div>
      
      <div style={styles.controlSection}>
        <h4 style={styles.subHeading}>Actions</h4>
        <div style={styles.buttonGroup}>
          <button 
            style={{
              ...styles.button,
              ...(isPinned ? styles.pinnedButton : {})
            }}
            onClick={() => handleActionClick(isPinned ? 'unpin' : 'pin')}
          >
            {isPinned ? 'Unpin' : 'Pin'}
          </button>
          <button 
            style={styles.button}
            onClick={() => handleActionClick('duplicate')}
          >
            Duplicate
          </button>
          <button 
            style={{...styles.button, ...styles.dangerButton}}
            onClick={() => handleActionClick('delete')}
          >
            Delete
          </button>
        </div>
      </div>
      
      <div style={styles.shortcutHints}>
        <p>Shortcuts: T (move), R (rotate), S (scale), P (pin/unpin)</p>
      </div>
    </div>
  );
};

export default ObjectControls;
